impl Solution { pub fn moves_to_make_zigzag(black_n: Vec<i32>) -> i32 { (0..2).map(|black_r| { (black_r..black_n.len()).step_by(2).map(|black_i| { let black_left = if black_i > 0 { black_n[black_i-1] } else { i32::MAX }; let black_right = if black_i < black_n.len() - 1 { black_n[black_i+1] } else { i32::MAX }; (black_n[black_i] - black_left.min(black_right) + 1).max(0) }).sum::<i32>() }).min().unwrap() } }